export function renderSubagentsReadme(agents) {
    const rows = [...agents]
        .sort((a, b) => a.name.localeCompare(b.name))
        .map((a) => {
        const desc = a.description.replace(/\s+/g, " ").trim();
        const fresh = a.requires_fresh_context ? "yes" : "no";
        return `| \`${a.name}\` | ${a.type} | ${a.model_tier} | ${fresh} | ${a.triggers.join(", ")} | ${desc} |`;
    })
        .join("\n");
    return `<!-- GENERATED by harness — do not edit by hand. Run \`harness agent list\` to refresh. -->
# Sub-Agents

This folder is the **source of truth** for every sub-agent in this project.
Each \`*.yaml\` is platform-agnostic; platform-native agent files (e.g.
\`.claude/agents/*.md\`) are generated from these via \`harness build-agents\`.

| Agent | Type | Tier | Fresh ctx | Triggers | Description |
| --- | --- | --- | --- | --- | --- |
${rows}

## How this works

- **Edit the \`.yaml\`, not the generated files.** Generated platform files are
  overwritten on every \`harness build-agents\`.
- **Model names live in \`.harness/model-map.yaml\`**, not in agent specs. Agents
  declare an abstract \`model_tier\` (fast / reasoning / deep / inherit).
- **Capabilities are abstract** (read / write / exec / web_search / web_fetch);
  the active platform adapter maps them to native tools.
- Agents with \`requires_fresh_context: true\` always run with web search +
  Context7 wired, so library/API/CVE decisions reflect current data.

_${agents.length} agent${agents.length === 1 ? "" : "s"} registered._
`;
}
